def dois_maiores(lista):
    if len(lista) < 2:
        return None, None   # ou seja não temos suficientes dados para comparar os elementos na posições 0 e 1.        

    maior = max(lista[0], lista[1])          # primeiro elemento é sempre o máximo do que já conseguimos, logo pula-se a verificação aqui com os outros elementos da segunda posição em diante.       
    mais_alto = min(lista[0], lista[1])       # mesmo sentido para primeiro elemento e quem é o máximo do que já conseguimos, logo pula-se a verificação aqui com os outros elementos da segunda posição em diante.

    for i in range(2):                        # vai rodar pela lista de 3 até o fim (só tem mais do que duas comparações)     
        if lista[i] > maior:                  # se os novos elementos são grandes, eles vão prevalecer ao da "maior" e preciso recomputar para verificar o restante. 
            segundo_maior = maior               # é como se um cache (para salvar) fosse usado aqui: guarda-me na primeira rodada, não tenha esquecido da "segunda" e ainda tive que comparar os outros elementos.     
            maior = lista[i]                    # agora faço o update do meu cache (primeiro) para ter em média usado na próxima rodada, não preciso percorrer toda minha primeira fila quando chego a segunda posições.
        elif lista[i] > mais_alto:              # se os novos elementos são grandes e estiverem no mesmo ou em um intervalo entre as anteriores, atualize o "mais alto" (para que a segunda posição continue sendo válida)
            mais_alto = lista[i]               # uma maneira de fazer cache e evitar rodar pela fila com os valores anteriores.  

    return ((segundo_maior, maior), (mais_alto, maior)) if segundo_maior and mais_alto else None # se não temos suficientes dados para comparar a terceira posições e posteriormente.

